# Resolve all log paths to absolute using APP_ROOT so services in
# subdirectories (PyInstaller one-dir builds) always write to the
# central logs/ folder.
def _resolve_log_path(env_var, default_filename):
    """Return an absolute log path.  Uses the env-var value when set,
    otherwise falls back to ``<APP_ROOT>/logs/<default_filename>``."""
    raw = os.getenv(env_var)
    if raw:
        return os.path.join(_APP_ROOT, raw) if not os.path.isabs(raw) else raw
    return os.path.join(_APP_ROOT, 'logs', default_filename)

