# Function to override config parameters from user_config.py if it exists os.getcwd()
def load_user_config():
    user_config_path = os.path.join(_APP_ROOT, "user_config.py")
    if os.path.exists(user_config_path):
        try:
            # Create a namespace to execute the user_config in
            user_config_namespace = {}
            with open(user_config_path, "r") as f:
                code = compile(f.read(), user_config_path, 'exec')
                exec(code, user_config_namespace)
            
            # Update the current module's globals with values from user_config
            import sys
            current_module = sys.modules[__name__]
            for key, value in user_config_namespace.items():
                if not key.startswith('__'):  # Skip special Python variables
                    setattr(current_module, key, value)
                    print(f"Override applied: {key} = {value}")
        except Exception as e:
            print(f"Failed to load user_config: {e}")

# Load user-defined configuration parameters
load_user_config()
